            <div style={{ width: 48, height: 48, borderRadius: 12, background: '#f1f5f9', margin: '0 auto 10px', display: 'flex', alignItems: 'center', justifyContent: 'center', fontSize: 22 }}>{icons[c.service_type] || '📞'}</div>
